#include<bits/stdc++.h>
using namespace std;

bool flag;
int n, a, b, c, d, e, f, num = 1, num2 = 0;
int main() {
	cin >> n;
	cin >> a >> b >> c >> d >> e >> f;
	for (int i = 0; i < n; i++) {
		cin >> flag;
		if (flag) {
			if (num >= 365) {
				num++;
				num2 += f;
			} else if (num >= 120) {
				num++;
				num2 += e;
			} else if (num >= 30) {
				num++;
				num2 += d;
			} else if (num >= 7) {
				num++;
				num2 += c;
			} else if (num >= 3) {
				num++;
				num2 += b;
			} else {
				num++;
				num2 += a;
			}
		} else {
			num = 1;
		}
	}cout<<num2;
	return 0;
}
